import Gygestest_board = [[0, 1, 3, 0, 2, 0],              [0, 0, 0, 3, 0, 0],              [0, 0, 0, 2, 0, 0],              [0, 0, 0, 2, 0, 0],              [0, 0, 3, 1, 0, 0],              [0, 2, 0, 1, 3, 1],              0, 0]if __name__ == '__main__':    board = Gyges.Board(test_board)    print(board)    best_moves = Gyges.best_move(board, depth=1)    for item_idx, item in enumerate(best_moves):        print(f"{item_idx + 1}. {item}")